import React, { useState } from 'react';

const PlaylistManager = ({ tracks, playlists, setPlaylists, currentTrackId, onTogglePlay }) => {
    const [selectedTrack, setSelectedTrack] = useState(null);
    const [showAddModal, setShowAddModal] = useState(false);
    
    const playlistNames = Object.keys(playlists);

    const addToPlaylist = (playlistName, trackId) => {
        if (!playlists[playlistName].includes(trackId)) {
            setPlaylists({
                ...playlists,
                [playlistName]: [...playlists[playlistName], trackId]
            });
        }
        setShowAddModal(false);
        setSelectedTrack(null);
    };

    const createPlaylist = () => {
        const name = prompt('Р’РІРµРґРёС‚Рµ РЅР°Р·РІР°РЅРёРµ РЅРѕРІРѕРіРѕ РїР»РµР№Р»РёСЃС‚Р°:');
        if (name && !playlists[name]) {
            setPlaylists({
                ...playlists,
                [name]: []
            });
        }
    };

    return (
        <div>
            <div className="view-header">
                <h2>РњРѕРё РїР»РµР№Р»РёСЃС‚С‹</h2>
                <button onClick={createPlaylist} className="primary-btn">+ РќРѕРІС‹Р№ РїР»РµР№Р»РёСЃС‚</button>
            </div>
            
            {playlistNames.length === 0 ? (
                <p className="placeholder">РЈ РІР°СЃ РїРѕРєР° РЅРµС‚ РїР»РµР№Р»РёСЃС‚РѕРІ. РЎРѕР·РґР°Р№С‚Рµ РїРµСЂРІС‹Р№!</p>
            ) : (
                playlistNames.map(playlistName => (
                    <div key={playlistName} className="playlist-section">
                        <h3>{playlistName} ({playlists[playlistName].length})</h3>
                        <div className="track-list compact">
                            {playlists[playlistName].map(trackId => {
                                const track = tracks.find(t => t.id === trackId);
                                if (!track) return null;
                                return (
                                    <div key={track.id} className="track-item compact">
                                        <span>{track.title} вЂ” {track.artist}</span>
                                        <button onClick={() => onTogglePlay(track.id)} className="icon-btn">
                                            {currentTrackId === track.id ? 'вЏёпёЏ' : 'в–¶пёЏ'}
                                        </button>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))
            )}

            <div className="view-header" style={{ marginTop: '30px' }}>
                <h3>Р”РѕР±Р°РІРёС‚СЊ С‚СЂРµРє РІ РїР»РµР№Р»РёСЃС‚</h3>
            </div>
            
            <div className="track-list">
                {tracks.map(track => (
                    <div key={track.id} className="track-item">
                        <div className="track-info">
                            <strong>{track.title}</strong>
                            <span>{track.artist}</span>
                        </div>
                        <div className="track-actions">
                            <select 
                                onChange={(e) => addToPlaylist(e.target.value, track.id)}
                                defaultValue=""
                                style={{ marginRight: '10px', padding: '5px' }}
                            >
                                <option value="" disabled>Р”РѕР±Р°РІРёС‚СЊ РІ...</option>
                                {playlistNames.map(name => (
                                    <option key={name} value={name}>{name}</option>
                                ))}
                            </select>
                            <button onClick={() => onTogglePlay(track.id)} className="icon-btn">
                                {currentTrackId === track.id ? 'вЏёпёЏ' : 'в–¶пёЏ'}
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default PlaylistManager;
